INSERT INTO doctors (name, slug, qualification, specialization, experience, bio, overall_success_rate, complication_rate, avg_recovery_time, languages) VALUES
('Dr. Nishant Sunkarineni', 'dr-nishant-sunkarineni', 'MBBS, MD, DM (Cardiology)', 'Interventional Cardiology', '10+ years', 'Consultant Interventional Cardiologist at Nikhil Hospital, Srinagar Colony, Hyderabad. Specializes in coronary and peripheral vascular interventions, structural heart disease management, and minimally invasive cardiac procedures.', 96, 1.5, '3-5 days', ARRAY['English', 'Hindi', 'Telugu']),
('Dr. Sibasankar Dalai', 'dr-sibasankar-dalai', 'MD, FACP, FINR (Neurology)', 'Neuro Vascular Intervention', '14+ years', 'Senior Consultant Neurovascular Interventionist at Medicover Hospital, Visakhapatnam. Fellow of American College of Physicians (FACP) and Fellow in Neurointerventional Radiology (FINR). Expert in stroke intervention, cerebral aneurysm coiling, and neuro-endovascular procedures.', 94, 2.0, '5-7 days', ARRAY['English', 'Hindi', 'Odia', 'Telugu']),
('Dr. Bhavyasree', 'dr-bhavyasree', 'MBBS, MD (Radiology)', 'Interventional Radiology', '5+ years', 'Consultant Interventional Radiologist at Gleneagles Hospital, Richmond Road, Bangalore. Trained in diagnostic and interventional radiology with expertise in uterine fibroid embolization, varicose vein treatment, and image-guided biopsies.', 95, 1.8, '2-4 days', ARRAY['English', 'Hindi', 'Kannada', 'Telugu']),
('Dr. Ankit', 'dr-ankit', 'MBBS, MD (Radiology)', 'Interventional Radiology', '5+ years', 'Consultant Interventional Radiologist at Trustwell Hospital, Bangalore. Specializes in minimally invasive vascular procedures including varicose vein treatment, varicocele embolization, and peripheral angioplasty.', 94, 2.0, '2-4 days', ARRAY['English', 'Hindi', 'Kannada']),
('Dr. Mandeep Sagar', 'dr-mandeep-sagar', 'MBBS, MD (Radiology)', 'Interventional Radiology', '8+ years', 'Consultant Interventional Radiologist at Tara Hospital, Mangalore. Experienced in varicose vein embolization, uterine fibroid embolization, and image-guided drainage procedures. Known for patient-centric approach to minimally invasive treatments.', 95, 1.5, '2-4 days', ARRAY['English', 'Hindi', 'Kannada', 'Tulu']),
('Dr. Periyalaruppan', 'dr-periyalaruppan', 'MBBS, MD (Radiology)', 'Interventional Radiology', '10+ years', 'Senior Consultant Interventional Radiologist at Anderson Diagnostics & Labs, Chennai. Over a decade of experience in image-guided interventions, vascular procedures, and minimally invasive treatments for various conditions.', 96, 1.2, '2-3 days', ARRAY['English', 'Hindi', 'Tamil']),
('Dr. Arul', 'dr-arul', 'MBBS, MD (Radiology)', 'Interventional Radiology', '8+ years', 'Consultant Interventional Radiologist at RPS Hospital, Chennai. Specializes in varicose vein treatment, uterine fibroid embolization, and peripheral vascular interventions with a focus on patient comfort and quick recovery.', 95, 1.8, '2-4 days', ARRAY['English', 'Hindi', 'Tamil']),
('Dr. Muthurajan', 'dr-muthurajan', 'MBBS, MD (Radiology)', 'Interventional Radiology', '10+ years', 'Senior Consultant Interventional Radiologist at Sri Ramakrishna Hospital, Coimbatore. Experienced in a wide range of vascular and non-vascular interventional procedures. Known for precision and excellent patient outcomes.', 96, 1.3, '2-3 days', ARRAY['English', 'Hindi', 'Tamil']),
('Dr. Raj Soni', 'dr-raj-soni', 'MBBS, MD (Radiology)', 'Interventional Radiology', '8+ years', 'Consultant Interventional Radiologist at Aartham Hospital, Ahmedabad. Specializes in varicose vein treatment, varicocele embolization, uterine fibroid embolization, and various image-guided minimally invasive procedures.', 95, 1.5, '2-4 days', ARRAY['English', 'Hindi', 'Gujarati']),
('Dr. Partha Pratim', 'dr-partha-pratim', 'MBBS, MD (Radiology)', 'Interventional Radiology', '12+ years', 'Senior Consultant Interventional Radiologist at Manipal Hospital, Kolkata. Over 12 years of experience in vascular and non-vascular interventional radiology. Expert in complex peripheral vascular interventions and tumor ablation procedures.', 96, 1.2, '3-5 days', ARRAY['English', 'Hindi', 'Bengali']),
('Dr. Praveen Keshav', 'dr-praveen-keshav', 'MBBS, MD (Radiology)', 'Interventional Radiology', '8+ years', 'Consultant Interventional Radiologist at GG Hospital, Trivandrum. Specializes in varicose vein embolization, uterine fibroid treatment, and peripheral vascular interventions with a focus on evidence-based minimally invasive care.', 95, 1.5, '2-4 days', ARRAY['English', 'Hindi', 'Malayalam']),
('Dr. Manish Kumar Yadav', 'dr-manish-kumar-yadav', 'MBBS, MD (Radiology)', 'Interventional Radiology', '8+ years', 'Consultant Interventional Radiologist at KIMS Hospital, Trivandrum. Experienced in varicose vein treatment, uterine fibroid embolization, varicocele treatment, and image-guided drainage procedures.', 95, 1.8, '2-4 days', ARRAY['English', 'Hindi', 'Malayalam']),
('Dr. Jithu Subash Babu', 'dr-jithu-subash-babu', 'MBBS, MD (Radiology)', 'Interventional Radiology', '6+ years', 'Consultant Interventional Radiologist at Baby Memorial Hospital, Calicut. Specializes in minimally invasive vascular procedures and image-guided interventions for various medical conditions.', 94, 2.0, '2-4 days', ARRAY['English', 'Hindi', 'Malayalam']),
('Dr. Thoufiq Ali', 'dr-thoufiq-ali', 'MBBS, MD (Radiology)', 'Interventional Radiology', '6+ years', 'Consultant Interventional Radiologist at KIMS Hospital, Perinthalmanna. Skilled in varicose vein treatment, varicocele embolization, and other minimally invasive vascular procedures.', 94, 2.0, '2-4 days', ARRAY['English', 'Hindi', 'Malayalam']),
('Dr. T. Seetam Kumar', 'dr-t-seetam-kumar', 'MBBS, MD (Radiology)', 'Interventional Radiology', '8+ years', 'Consultant Interventional Radiologist at Manipal Hospital, Bhubaneswar. Specializes in image-guided minimally invasive procedures including vascular interventions, tumor ablations, and drainage procedures.', 95, 1.5, '2-4 days', ARRAY['English', 'Hindi', 'Odia']);
